import { Component, inject } from '@angular/core';
import { CommonModule } from '@angular/common';
import { ReactiveFormsModule, FormBuilder, Validators } from '@angular/forms';
import { RouterLink, ActivatedRoute } from '@angular/router';
import { BoatStatus, BoatType } from '../../core/models';

@Component({
  selector: 'app-boat-form',
  standalone: true,
  imports: [CommonModule, ReactiveFormsModule, RouterLink],
  templateUrl: './boat-form.component.html',
})
export class BoatFormComponent {
  private fb = inject(FormBuilder);
  private id = inject(ActivatedRoute).snapshot.paramMap.get('id');

  readonly isEdit = !!this.id;

  readonly types: { value: BoatType; label: string }[] = [
    { value: 'ONE_X', label: '1x — Single' },
    { value: 'TWO_X', label: '2x — Double' },
    { value: 'FOUR_PLUS', label: '4+ — Coxed four' },
    { value: 'EIGHT_PLUS', label: '8+ — Eight' },
  ];

  readonly statuses: BoatStatus[] = ['active', 'maintenance', 'retired'];

  form = this.fb.group({
    name: [this.isEdit ? 'Morning Star' : '', [Validators.required]],
    type: [this.isEdit ? 'ONE_X' : 'ONE_X', [Validators.required]],
    seats: [this.isEdit ? 1 : 1, [Validators.required, Validators.min(1)]],
    status: [this.isEdit ? 'active' : 'active', [Validators.required]],
  });

  submit(): void {
    if (this.form.invalid) {
      this.form.markAllAsTouched();
    }
    // service_agent wires this to ApiService.createBoat / updateBoat.
  }
}
